/* Simple ABR (adaptive bitrate) selection pseudo-code used client-side to pick next segment bitrate */
function selectBitrate(availableRates, measuredBandwidthKbps, bufferSec) {
  // conservative fraction of measured bandwidth to account for volatility
  const safetyFactor = 0.7;
  const targetKbps = measuredBandwidthKbps * safetyFactor;

  // prefer higher quality when buffer is healthy
  const bufferBias = bufferSec > 10 ? 1.2 : bufferSec < 5 ? 0.8 : 1.0;
  const effectiveTarget = targetKbps * bufferBias;

  // pick the highest rate that is <= effectiveTarget
  let pick = availableRates[0];
  for (const r of availableRates) {
    if (r.kbps <= effectiveTarget) pick = r;
  }
  return pick;
}

/* In practice Netflix clients combine many signals (manifest, CDN hinting, ABR models and telemetry) */
